1	/**
2	 * Guild lifecycle — pure logic for plugin validation, ordering, and events.
3	 *
4	 * All functions here operate on in-memory data structures (LoadedKit[],
5	 * LoadedApparatus[], Maps) with no I/O. This makes them independently
6	 * testable with synthetic fixtures.
7	 *
8	 * `createGuild()` in arbor.ts is the orchestrator that performs I/O
9	 * (config reading, dynamic imports) then delegates to these functions.
10	 */
11	
12	import type {
13	  StartupContext,
14	  KitEntry,
15	  LoadedKit,
16	  LoadedApparatus,
17	  FailedPlugin,
18	} from '@shardworks/nexus-core';
19	
20	// ── Types ────────────────────────────────────────────────────────────
21	
22	export type EventHandlerMap = Map<
23	  string,
24	  Array<(...args: unknown[]) => void | Promise<void>>
25	>;
26	
27	// ── Validation ───────────────────────────────────────────────────────
28	
29	/**
30	 * Validate all `requires` declarations and detect circular dependencies.
31	 * Returns an array of FailedPlugin entries describing every problem found.
32	 *
33	 * Checks:
34	 * - Apparatus requires: every named dependency must exist (kit or apparatus).
35	 * - Kit requires: every named dependency must be an apparatus (kits can't
36	 *   depend on kits).
37	 * - Cycle detection: no circular dependency chains among apparatuses.
38	 */
39	export function validateRequires(
40	  kits: LoadedKit[],
41	  apparatuses: LoadedApparatus[],
42	): FailedPlugin[] {
43	  const failures: FailedPlugin[] = [];
44	  const failedIds = new Set<string>();
45	
46	  const apparatusIds = new Set(apparatuses.map((a) => a.id));
47	  const allIds = new Set([
48	    ...kits.map((k) => k.id),
49	    ...apparatuses.map((a) => a.id),
50	  ]);
51	
52	  // Check apparatus requires
53	  for (const app of apparatuses) {
54	    for (const dep of app.apparatus.requires ?? []) {
55	      if (!allIds.has(dep)) {
56	        if (!failedIds.has(app.id)) {
57	          failedIds.add(app.id);
58	          failures.push({
59	            id:     app.id,
60	            reason: `"${app.id}" requires "${dep}", which is not installed.`,
61	          });
62	        }
63	      }
64	    }
65	  }
66	
67	  // Check kit requires (must be apparatus names — kits can't depend on kits)
68	  for (const kit of kits) {
69	    for (const dep of kit.kit.requires ?? []) {
70	      if (!apparatusIds.has(dep)) {
71	        if (!failedIds.has(kit.id)) {
72	          failedIds.add(kit.id);
73	          if (!allIds.has(dep)) {
74	            failures.push({
75	              id:     kit.id,
76	              reason: `kit "${kit.id}" requires "${dep}", which is not installed.`,
77	            });
78	          } else {
79	            failures.push({
80	              id:     kit.id,
81	              reason: `kit "${kit.id}" requires "${dep}", but that plugin is a kit, not an apparatus. Kit requires must name apparatus plugins.`,
82	            });
83	          }
84	        }
85	      }
86	    }
87	  }
88	
89	  // Detect circular dependencies among apparatuses
90	  const visiting = new Set<string>();
91	  const visited = new Set<string>();
92	  const cycleParticipants = new Set<string>();
93	
94	  function visit(id: string, chain: string[]): void {
95	    if (visited.has(id)) return;
96	    if (visiting.has(id)) {
97	      // Back-edge detected — extract cycle participants from chain
98	      const cycleStart = chain.indexOf(id);
99	      const cycleNodes = cycleStart >= 0 ? chain.slice(cycleStart) : [...chain];
100	      cycleNodes.push(id);
101	      for (const node of cycleNodes) {
102	        cycleParticipants.add(node);
103	      }
104	      return;
105	    }
106	    visiting.add(id);
107	    const app = apparatuses.find((a) => a.id === id);
108	    if (app) {
109	      for (const dep of app.apparatus.requires ?? []) {
110	        visit(dep, [...chain, id]);
111	      }
112	    }
113	    visiting.delete(id);
114	    visited.add(id);
115	  }
116	
117	  for (const app of apparatuses) {
118	    visit(app.id, []);
119	  }
120	
121	  for (const id of cycleParticipants) {
122	    if (!failedIds.has(id)) {
123	      failedIds.add(id);
124	      failures.push({
125	        id,
126	        reason: `"${id}" is part of a circular dependency chain.`,
127	      });
128	    }
129	  }
130	
131	  return failures;
132	}
133	
134	// ── Cascade filtering ─────────────────────────────────────────────────
135	
136	/**
137	 * Remove plugins that transitively depend on any failed plugin.
138	 *
139	 * Iterates until stable, cascading failures through the dependency graph.
140	 * Returns healthy plugins and any newly-cascaded failures.
141	 */
142	export function filterFailedPlugins(
143	  kits: LoadedKit[],
144	  apparatuses: LoadedApparatus[],
145	  rootFailures: FailedPlugin[],
146	): { kits: LoadedKit[]; apparatuses: LoadedApparatus[]; cascaded: FailedPlugin[] } {
147	  const failedIds = new Set<string>(rootFailures.map((f) => f.id));
148	  const cascaded: FailedPlugin[] = [];
149	
150	  // Apparatus cascade: iterate until no new failures
151	  let changed = true;
152	  while (changed) {
153	    changed = false;
154	    for (const app of apparatuses) {
155	      if (failedIds.has(app.id)) continue;
156	      for (const dep of app.apparatus.requires ?? []) {
157	        if (failedIds.has(dep)) {
158	          failedIds.add(app.id);
159	          cascaded.push({
160	            id:     app.id,
161	            reason: `"${app.id}" depends on failed plugin "${dep}".`,
162	          });
163	          changed = true;
164	          break;
165	        }
166	      }
167	    }
168	  }
169	
170	  // Kit cascade: single pass (kits can't depend on other kits)
171	  for (const kit of kits) {
172	    if (failedIds.has(kit.id)) continue;
173	    for (const dep of kit.kit.requires ?? []) {
174	      if (failedIds.has(dep)) {
175	        failedIds.add(kit.id);
176	        cascaded.push({
177	          id:     kit.id,
178	          reason: `"${kit.id}" depends on failed plugin "${dep}".`,
179	        });
180	        break;
181	      }
182	    }
183	  }
184	
185	  return {
186	    kits:        kits.filter((k) => !failedIds.has(k.id)),
187	    apparatuses: apparatuses.filter((a) => !failedIds.has(a.id)),
188	    cascaded,
189	  };
190	}
191	
192	// ── Dependency ordering ──────────────────────────────────────────────
193	
194	/**
195	 * Sort apparatuses in dependency-resolved order using topological sort.
196	 * validateRequires() must be called first to ensure the graph is acyclic.
197	 */
198	export function topoSort(apparatuses: LoadedApparatus[]): LoadedApparatus[] {
199	  const sorted: LoadedApparatus[] = [];
200	  const visited = new Set<string>();
201	
202	  function visit(id: string): void {
203	    if (visited.has(id)) return;
204	    const app = apparatuses.find((a) => a.id === id);
205	    if (!app) return;
206	    for (const dep of app.apparatus.requires ?? []) {
207	      visit(dep);
208	    }
209	    visited.add(id);
210	    sorted.push(app);
211	  }
212	
213	  for (const app of apparatuses) {
214	    visit(app.id);
215	  }
216	
217	  return sorted;
218	}
219	
220	// ── Wire phase ───────────────────────────────────────────────────────
221	
222	/** Framework-level kit fields excluded from KitEntry collection. */
223	const FRAMEWORK_KIT_FIELDS = new Set(['requires', 'recommends']);
224	
225	/**
226	 * Collect all kit contributions from standalone kits and apparatus supportKits
227	 * into a flat KitEntry array. Called during the Wire phase before any start().
228	 *
229	 * Iteration order: standalone kits first, then ordered apparatuses.
230	 * Framework fields (requires, recommends) are excluded.
231	 */
232	export function wireKitEntries(
233	  kits: LoadedKit[],
234	  orderedApparatuses: LoadedApparatus[],
235	): KitEntry[] {
236	  const entries: KitEntry[] = [];
237	
238	  for (const kit of kits) {
239	    for (const [type, value] of Object.entries(kit.kit)) {
240	      if (FRAMEWORK_KIT_FIELDS.has(type)) continue;
241	      entries.push({ pluginId: kit.id, packageName: kit.packageName, type, value });
242	    }
243	  }
244	
245	  for (const app of orderedApparatuses) {
246	    const bag = app.apparatus.supportKit;
247	    if (!bag || typeof bag !== 'object') continue;
248	    for (const [type, value] of Object.entries(bag)) {
249	      if (FRAMEWORK_KIT_FIELDS.has(type)) continue;
250	      entries.push({ pluginId: app.id, packageName: app.packageName, type, value });
251	    }
252	  }
253	
254	  return entries;
255	}
256	
257	// ── Startup warnings ─────────────────────────────────────────────────
258	
259	/**
260	 * Collect advisory warnings for kit contributions that no apparatus
261	 * consumes, and for missing recommended apparatuses.
262	 *
263	 * Returns an array of warning strings. The caller decides how to emit
264	 * them (console.warn, logger, etc.).
265	 */
266	export function collectStartupWarnings(
267	  kits:        LoadedKit[],
268	  apparatuses: LoadedApparatus[],
269	): string[] {
270	  const warnings: string[] = [];
271	  const consumedTypes = new Set<string>();
272	  const installedIds  = new Set(apparatuses.map((a) => a.id));
273	
274	  for (const app of apparatuses) {
275	    for (const token of app.apparatus.consumes ?? []) {
276	      consumedTypes.add(token);
277	    }
278	  }
279	
280	  // Check apparatus recommends
281	  for (const app of apparatuses) {
282	    for (const rec of app.apparatus.recommends ?? []) {
283	      if (!installedIds.has(rec)) {
284	        warnings.push(
285	          `[arbor] warn: "${app.id}" recommends "${rec}" but it is not installed.`,
286	        );
287	      }
288	    }
289	  }
290	
291	  for (const kit of kits) {
292	    // Check kit recommends
293	    for (const rec of kit.kit.recommends ?? []) {
294	      if (!installedIds.has(rec)) {
295	        warnings.push(
296	          `[arbor] warn: "${kit.id}" recommends "${rec}" but it is not installed.`,
297	        );
298	      }
299	    }
300	
301	    // Check contribution types against consumes
302	    for (const key of Object.keys(kit.kit)) {
303	      if (key === 'requires' || key === 'recommends') continue;
304	      if (!consumedTypes.has(key)) {
305	        warnings.push(
306	          `[arbor] warn: "${kit.id}" contributes "${key}" but no installed apparatus declares consumes: ["${key}"]`,
307	        );
308	      }
309	    }
310	  }
311	
312	  // Check apparatus supportKit contribution types against consumes
313	  for (const app of apparatuses) {
314	    if (!app.apparatus.supportKit) continue;
315	    for (const key of Object.keys(app.apparatus.supportKit)) {
316	      if (key === 'requires' || key === 'recommends') continue;
317	      if (!consumedTypes.has(key)) {
318	        warnings.push(
319	          `[arbor] warn: "${app.id}" supportKit contributes "${key}" but no installed apparatus declares consumes: ["${key}"]`,
320	        );
321	      }
322	    }
323	  }
324	
325	  return warnings;
326	}
327	
328	// ── Event system ─────────────────────────────────────────────────────
329	
330	/**
331	 * Build a StartupContext for an apparatus's start() call.
332	 * The context provides event subscription and kit contribution queries.
333	 * Handlers are stored in the shared eventHandlers map so fireEvent can
334	 * invoke them later. Kit entries are pre-indexed by type for efficient lookup.
335	 */
336	export function buildStartupContext(
337	  eventHandlers: EventHandlerMap,
338	  kitEntries: KitEntry[],
339	): StartupContext {
340	  // Pre-index by type for efficient lookup
341	  const index = new Map<string, KitEntry[]>();
342	  for (const entry of kitEntries) {
343	    const list = index.get(entry.type) ?? [];
344	    list.push(entry);
345	    index.set(entry.type, list);
346	  }
347	
348	  return {
349	    on(event: string, handler: (...args: unknown[]) => void | Promise<void>) {
350	      const list = eventHandlers.get(event) ?? [];
351	      list.push(handler);
352	      eventHandlers.set(event, list);
353	    },
354	
355	    kits(type: string): KitEntry[] {
356	      return [...(index.get(type) ?? [])];
357	    },
358	  };
359	}
360	
361	/**
362	 * Fire a lifecycle event, awaiting each handler sequentially.
363	 */
364	export async function fireEvent(
365	  eventHandlers: EventHandlerMap,
366	  event:         string,
367	  ...args: unknown[]
368	): Promise<void> {
369	  const handlers = eventHandlers.get(event) ?? [];
370	  for (const h of handlers) {
371	    await h(...args);
372	  }
373	}
374	
375	// ── Shutdown ─────────────────────────────────────────────────────────
376	
377	/**
378	 * Per-apparatus failure produced by `shutdownStartedApparatuses` when one
379	 * or more `stop()` invocations throw. Each entry pairs the apparatus
380	 * plugin id with the underlying error so the aggregate caller can
